    public static str removeDuplicateWords(str input, str separator)
    {
        container   wordsContainer;
        Map         seenWords = new Map(Types::String, Types::Enum);
        container   result;
        str         word;
        int         i;

        //Split the string
        wordsContainer = str2con(input, separator);
    
        // loop the word and add it when not doublon
        for (i = 1; i <= conLen(wordsContainer); i++)
        {
            word = conPeek(wordsContainer, i);

            if (!seenWords.exists(word))
            {
                result += word;
                seenWords.insert(word, true);
            }
        }

        //rebuild the string
        return con2Str(result,separator);
    }
